// 1. Sadə sinif və interface
interface Animal {
  name: string;
  makeSound(): string;
}
class Dog implements Animal {
  name: string;
  constructor(name: string) {
    this.name = name;
  }
  makeSound(): string {
    return "Woof!";
  }
}
const dog = new Dog("Buddy");
console.log(dog.name); // Çıxış: Buddy
console.log(dog.makeSound()); // Çıxış: Woof!

// 2. Çoxlu interfeyslərin tətbiqi
interface Pet {
  owner: string;
}
class Cat implements Animal, Pet {
  name: string;
  owner: string;
  constructor(name: string, owner: string) {
    this.name = name;
    this.owner = owner;
  }
  makeSound(): string {
    return "Meow!";
  }
}
const cat = new Cat("Whiskers", "Alice");
console.log(cat); // Çıxış: Cat { name: "Whiskers", owner: "Alice" }
console.log(cat.makeSound()); // Çıxış: Meow!

// 3. Optional və readonly xüsusiyyətlər
interface Vehicle {
  readonly brand: string;
  model?: string;
  getInfo(): string;
}
class Car implements Vehicle {
  readonly brand: string;
  model?: string;
  constructor(brand: string, model?: string) {
    this.brand = brand;
    this.model = model;
  }
  getInfo(): string {
    return this.model ? `${this.brand} ${this.model}` : this.brand;
  }
}
const car = new Car("Toyota", "Camry");
console.log(car.getInfo()); // Çıxış: Toyota Camry
// car.brand = "Honda"; // Xəta: readonly xüsusiyyət dəyişdirilə bilməz

// 4. Extends və implements birlikdə
interface Person {
  name: string;
}
interface Employee extends Person {
  role: string;
  work(): string;
}
class Manager extends Dog implements Employee {
  role: string;
  constructor(name: string, role: string) {
    super(name);
    this.role = role;
  }
  work(): string {
    return `${this.name} is managing the team.`;
  }
}
const manager = new Manager("Max", "Team Lead");
console.log(manager.work()); // Çıxış: Max is managing the team.
console.log(manager.makeSound()); // Çıxış: Woof!

// 5. Union tipləri ilə istifadə
interface Book {
  type: "book";
  title: string;
  pages: number;
}
interface Movie {
  type: "movie";
  title: string;
  duration: number;
}
type Media = Book | Movie;
interface MediaDisplay {
  display(): string;
}
class MediaItem implements MediaDisplay {
  media: Media;
  constructor(media: Media) {
    this.media = media;
  }
  display(): string {
    if (this.media.type === "book") {
      return `${this.media.title}: ${this.media.pages} pages`;
    }
    return `${this.media.title}: ${this.media.duration} minutes`;
  }
}
const book = new MediaItem({ type: "book", title: "TypeScript Guide", pages: 200 });
const movie = new MediaItem({ type: "movie", title: "Inception", duration: 148 });
console.log(book.display()); // Çıxış: TypeScript Guide: 200 pages
console.log(movie.display()); // Çıxış: Inception: 148 minutes

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price: number;
  getDetails(): string;
}
class ProductItem implements Product {
  id: string;
  name: string;
  price: number;
  inStock: boolean;
  constructor(id: string, name: string, price: number, inStock: boolean) {
    this.id = id;
    this.name = name;
    this.price = price;
    this.inStock = inStock;
  }
  getDetails(): string {
    return `${this.name} (ID: ${this.id}): $${this.price}, ${this.inStock ? "mövcuddur" : "mövcud deyil"}`;
  }
}
const laptop = new ProductItem("P001", "Laptop", 1200, true);
console.log(laptop.getDetails()); // Çıxış: Laptop (ID: P001): $1200, mövcuddur

// Extends və implements ilə
interface Stock {
  stockCount: number;
}
class StockProduct extends ProductItem implements Stock {
  stockCount: number;
  constructor(id: string, name: string, price: number, inStock: boolean, stockCount: number) {
    super(id, name, price, inStock);
    this.stockCount = stockCount;
  }
  getStockInfo(): string {
    return `${this.name}: ${this.stockCount} ədəd`;
  }
}
const stockLaptop = new StockProduct("P001", "Laptop", 1200, true, 10);
console.log(stockLaptop.getDetails()); // Çıxış: Laptop (ID: P001): $1200, mövcuddur
console.log(stockLaptop.getStockInfo()); // Çıxış: Laptop: 10 ədəd

